const express = require('express');
const MongoClient = require('mongodb').MongoClient;
const app = express();
app.use(express.json());

const MONGO_URL = 'mongodb://localhost:27017';
const DB_NAME = 'rate-limiting-api';
const COLLECTION_NAME = 'users';

MongoClient.connect(MONGO_URL, { useNewUrlParser: true, useUnifiedTopology: true }, (err, client) => {
  if (err) {
    console.error(err);
    return;
  }

  const db = client.db(DB_NAME);
  const collection = db.collection(COLLECTION_NAME);

  app.post('/users', (req, res) => {
    // Create a new user and add to the database
    const user = {
      id: req.body.id,
      name: req.body.name,
      email: req.body.email,
      requestHistory: []
    };

    collection.insertOne(user, (err, result) => {
      if (err) {
        console.error(err);
        res.status(500).send({ error: 'Failed to create user' });
      } else {
        res.send({ id: user.id });
      }
    });
  });

  app.get('/users/:id', (req, res) => {
    // Retrieve a user's information and request history
    collection.findOne({ id: req.params.id }, (err, user) => {
      if (err || !user) {
        console.error(err);
        res.status(404).send({ error: 'User not found' });
      } else {
        res.send(user);
      }
    });
  });

  app.post('/pages', (req, res) => {
    // Create a new high-traffic web page
    const page = {
      id: req.body.id,
      title: req.body.title,
      content: req.body.content
    };

    collection.insertOne(page, (err, result) => {
      if (err) {
        console.error(err);
        res.status(500).send({ error: 'Failed to create page' });
      } else {
        res.send({ id: page.id });
      }
    });
  });

  app.listen(3000, () => {
    console.log('Server running on port 3000');
  });
